import { FC } from 'react';

import { OneColumnLayoutProps } from '../Layout.types';

import { OneColumnLayout, Main } from './OneColumn.styles';

const OneColumn: FC<OneColumnLayoutProps> = ({ main, ...rest }) => {
  if (!main) return null;

  return (
    <OneColumnLayout {...rest}>
      <Main>{main}</Main>
    </OneColumnLayout>
  );
};
export default OneColumn;
